window.initFirebase = async function initFirebase() {
  try {
    const { initializeApp } = await import('https://www.gstatic.com/firebasejs/10.7.1/firebase-app.js');
    const { getMessaging, getToken, onMessage } = await import('https://www.gstatic.com/firebasejs/10.7.1/firebase-messaging.js');
    const app = initializeApp(FIREBASE_CONFIG);
    const messaging = getMessaging(app);
    const sw = await navigator.serviceWorker.register('/firebase-messaging-sw.js');
    const token = await getToken(messaging, { vapidKey: VAPID_KEY, serviceWorkerRegistration: sw });
    if (token) {
      console.log('FCM Token:', token);
      window._fcmToken = token;
    }
    onMessage(messaging, (payload) => {
      console.log('Messaggio ricevuto:', payload);
      // Mostra notifica anche quando app è in foreground
      const title = payload.notification?.title || payload.data?.title || 'Dolci Sapori';
      const body = payload.notification?.body || payload.data?.body || '';
      if(body && 'Notification' in window && Notification.permission === 'granted') {
        new Notification(title, {
          body,
          icon: '/logo192.png',
        });
      }
    });
  } catch(e) { console.log('Firebase init error:', e); }
}

// ─── Service Worker (PWA) ─────────────────────────────────────────────────
if ('serviceWorker' in navigator) {
  window.addEventListener('load', () => {
    navigator.serviceWorker.register('/service-worker.js')
      .then(reg => console.log('SW registrato:', reg.scope))
      .catch(err => console.log('SW errore:', err));
    // Inizializza Firebase dopo SW
    if (window.location.protocol === 'https:') {
      initFirebase().catch(console.error);
    }
  });
} /* eslint-disable */
