// ROOT
// ════════════════════════════════════════════════════════════════════════════
export default function App() {
  const [appState, setAppState] = useState(null);
  const [user,     setUser]     = useState(null);
  const saveTimer               = useRef(null);

  // ── Rimani loggato ──────────────────────────────────────────────────────
  useEffect(() => {
    try {
      const saved = localStorage.getItem("ds_logged_user");
      if (saved) setUser(JSON.parse(saved));
    } catch {}
  }, []);

  // Aggiorna i dati utente quando cambia appState (es. approvazione)
  useEffect(() => {
    if (!user || !appState) return;
    const fresh = appState.users.find(u => u.id === user.id);
    if (fresh && JSON.stringify(fresh) !== JSON.stringify(user)) {
      setUser(fresh);
      try { localStorage.setItem("ds_logged_user", JSON.stringify(fresh)); } catch {}
    }
  }, [appState]);

  const handleLogin = (u) => {
    setUser(u);
    try { localStorage.setItem("ds_logged_user", JSON.stringify(u)); } catch {}
    // Salva FCM token nel DB per questo utente
    setTimeout(async () => {
      try {
        // Prova a ottenere il token se non ancora disponibile
        if (!window._fcmToken && window.initFirebase) {
          await window.initFirebase();
          await new Promise(r=>setTimeout(r,2000));
        }
        if (window._fcmToken) {
          update(prev => ({fcmTokens: {...(prev.fcmTokens||{}), [u.id]: window._fcmToken}}));
        }
      } catch(e) { console.log("FCM token save error:", e); }
    }, 3000);
  };

  const handleLogout = () => {
    setUser(null);
    try { localStorage.removeItem("ds_logged_user"); } catch {}
  };

  useEffect(() => {
    loadState().then(s => setAppState(s));
    // Ricarica dal database ogni 5 secondi per sincronizzare tra dispositivi
    const poll = setInterval(() => {
      if (isSaving.current) return; // non sovrascrivere durante salvataggio
      loadState().then(s => setAppState(prev => {
        if (isSaving.current) return prev; // check di nuovo
        if (JSON.stringify(prev) !== JSON.stringify(s)) return s;
        return prev;
      }));
    }, 3000);
    return () => clearInterval(poll);
  }, []);



  const isSaving = useRef(false);

  const update = useCallback(patch => {
    setAppState(prev => {
      const next = typeof patch === 'function'
        ? {...prev,...patch(prev)}
        : {...prev,...patch};
      isSaving.current = true;
      saveState(next).finally(() => { isSaving.current = false; });
      return next;
    });
  }, []);

  if (!appState) return (
    <><style>{STYLE}</style>
    <div className="auth-wrap"><div style={{color:"var(--muted)"}}>Caricamento...</div></div></>
  );

  return (
    <><style>{STYLE}</style>
    <div className="app-bg" style={{backgroundImage:`url(${BRAND.bgImage})`}}/>
    {!user
      ? <AuthScreen appState={appState} update={update} onLogin={handleLogin}/>
      : user.role==="admin"
        ? <AdminPanel  user={user} appState={appState} update={update} onLogout={handleLogout}/>
        : <ClientPanel user={user} appState={appState} update={update} onLogout={handleLogout}/>
    }</>
  );
}

