// ADMIN – MENU
// ════════════════════════════════════════════════════════════════════════════
function AdminMenu({ date, appState, update }) {
  const [newName,     setNewName]     = useState("");
  const [newPrice,    setNewPrice]    = useState("");
  const [newCategoria,    setNewCategoria]    = useState("primi");
  const [toast,           setToast]           = useState({text:"",ok:true});
  const [editCustomAdmin, setEditCustomAdmin] = useState(null);
  const [editCustomAdminName, setEditCustomAdminName] = useState("");
  // Stato locale per aggiornare UI subito senza aspettare il polling
  const [localOrdersOpen, setLocalOrdersOpen] = useState(null);
  const showToast=(t,ok=true)=>{setToast({text:t,ok});setTimeout(()=>setToast({text:"",ok:true}),2400);};

  const items     = appState.menus[date] || [];
  const published  = appState.menuPub[date] || false;
  const ordersOpen = isOrdersOpen(date, appState);
  const saveItems = list => update({menus:{...appState.menus,[date]:list}});

  const add = () => {
    const name = newName.trim();
    const price = newPrice !== "" ? parseFloat(newPrice) : null;
    if (!name) return;
    setNewName(""); setNewPrice("");
    const newItem = {id:Date.now().toString(),name,price,custom:false,categoria:newCategoria};
    update(prev => ({menus:{...prev.menus,[date]:[...(prev.menus[date]||[]),newItem]}}));
  };
  const updatePrice = (id,val) => saveItems(items.map(i=>i.id===id?{...i,price:val===""?null:parseFloat(val)}:i));

  const duplicatePrev = () => {
    const prev = appState.menus[prevDay(date)];
    if (!prev||!prev.length){showToast("Nessun menù ieri da duplicare.",false);return;}
    const newItems = prev
      .filter(i=>!i.custom) // non duplicare piatti personalizzati di ieri
      .map(i=>({...i,id:Date.now().toString()+Math.random().toString(36).slice(2,5)}));
    saveItems(newItems); showToast("✓ Menù di ieri duplicato!");
  };

  const publish   = ()=>{update({menuPub:{...appState.menuPub,[date]:true}});  showToast("✓ Menù pubblicato!");};
  const unpublish = ()=>{update({menuPub:{...appState.menuPub,[date]:false}}); showToast("Menù nascosto.");};

  const openOrders = ()=>{
    const current = appState.ordersOpen || {};
    const msg = "🔓 Le ordinazioni sono aperte! Ordina subito.";
    const approved = appState.users.filter(u=>u.role!=="admin"&&u.approved);
    const newNotifs = {...appState.notifications};
    const now = new Date().toISOString();
    approved.forEach(u=>{
      newNotifs[u.id] = [{id:Date.now()+u.id,text:msg,date:now,read:false}, ...(newNotifs[u.id]||[])];
    });
    const patch = {ordersOpen:{...current,[date]:true}, notifications:newNotifs};
    update(patch);
    setLocalOrdersOpen(true);
    const fcmTokensAll = appState.fcmTokens||{};
    const fcmToks = appState.users.filter(u=>u.role!=="admin"&&u.approved).map(u=>fcmTokensAll[u.id]).filter(Boolean);
    if(fcmToks.length>0) sendPush("🔓 Ordini aperti", "Le ordinazioni sono aperte! Ordina subito.", fcmToks);
    showToast("✓ Ordini aperti! Notifica inviata.");
  };
  const closeOrders = ()=>{
    const currentOpen = appState.ordersOpen || {};
    // Notifiche a tutti i clienti
    const msg = "🔒 Le ordinazioni sono chiuse. Grazie!";
    const approved = appState.users.filter(u=>u.role!=="admin"&&u.approved);
    const newNotifs = {...appState.notifications};
    approved.forEach(u=>{
      newNotifs[u.id] = [{id:Date.now(),text:msg,date:new Date().toISOString(),read:false}, ...(newNotifs[u.id]||[])];
    });
    // Una sola chiamata update con tutto
    const patch = {ordersOpen:{...currentOpen,[date]:false}, notifications:newNotifs};
    update(patch);
    setLocalOrdersOpen(false);
    const fcmTokensClose = appState.fcmTokens||{};
    const fcmToksClose = appState.users.filter(u=>u.role!=="admin"&&u.approved).map(u=>fcmTokensClose[u.id]).filter(Boolean);
    if(fcmToksClose.length>0) sendPush("🔒 Ordini chiusi", "Le ordinazioni sono chiuse. Grazie!", fcmToksClose);
    showToast("🔒 Ordini chiusi, notifica inviata!");
  };

  const customItems = items.filter(i=>i.custom);
  const normalItems = items.filter(i=>!i.custom);

  return (
    <div className="card">
      <div className="card-title">
        📋 Menù — {fmt(date)}
        {published&&<span style={{fontSize:".68rem",background:"#e8f5ee",color:"var(--green)",border:"1px solid #99ccb0",borderRadius:20,padding:"2px 9px",fontWeight:700}}>● Pubblicato</span>}
      </div>

      {/* Piatti per categoria */}
      {normalItems.length===0&&customItems.length===0&&<div className="empty">Nessuna voce. Aggiungi o duplica da ieri.</div>}
      {CATEGORIE.map(cat=>{
        const catItems = normalItems.filter(i=>i.categoria===cat.id || (!i.categoria && cat.id==="primi"));
        if(catItems.length===0) return null;
        return(<div key={cat.id} style={{marginBottom:8}}>
          <div style={{fontSize:".75rem",fontWeight:700,color:"var(--accent)",margin:"10px 0 5px",
            textTransform:"uppercase",letterSpacing:".04em",borderBottom:"1px solid var(--border-lt)",paddingBottom:4}}>
            {cat.label}
          </div>
          {catItems.map(item=>(
        <div className="menu-item" key={item.id}>
          <span style={{fontWeight:700}}>{item.name}</span>
          <div className="flex">
            <span className="muted" style={{fontSize:".82rem"}}>€</span>
            <input style={{width:78,textAlign:"right",padding:"6px 7px"}} type="number" step="0.50" min="0" placeholder="—"
              value={item.price??""} onChange={e=>updatePrice(item.id,e.target.value)}/>
            <button className="btn btn-sm" style={{background:"#fdf0ee",color:"var(--red)",border:"1px solid #f0b9b4"}}
              onClick={()=>saveItems(items.filter(i=>i.id!==item.id))}>✕</button>
          </div>
        </div>
      ))}
        </div>
        );
      })}

      {/* Custom requests */}
      {customItems.length>0&&(
        <>
          <div style={{fontSize:".78rem",fontWeight:700,color:"var(--gold)",margin:"10px 0 6px",textTransform:"uppercase",letterSpacing:".04em"}}>⭐ Richieste personalizzate clienti</div>
          {customItems.map(item=>(
            <div className="menu-item menu-item-custom" key={item.id}>
              <div style={{flex:1}}>
                {editCustomAdmin===item.id
                  ? <div className="flex" style={{gap:6}}>
                      <input value={editCustomAdminName}
                        onChange={e=>setEditCustomAdminName(e.target.value)}
                        style={{flex:1,fontSize:".85rem"}} autoFocus
                        onKeyDown={e=>{ if(e.key==="Enter") {
                          const newName=editCustomAdminName.trim();
                          if(!newName) return;
                          // Aggiorna nel menù
                          const updMenu=items.map(i=>i.id===item.id?{...i,name:newName}:i);
                          saveItems(updMenu);
                          // Aggiorna negli ordini
                          const newOrders={...appState.orders};
                          Object.keys(newOrders).filter(k=>k.startsWith(date+":")).forEach(k=>{
                            const ord=newOrders[k];
                            if(ord&&ord.items.find(i=>i.id===item.id))
                              newOrders[k]={...ord,items:ord.items.map(i=>i.id===item.id?{...i,name:newName}:i)};
                          });
                          update({orders:newOrders});
                          setEditCustomAdmin(null);
                        }}}
                      />
                      <button className="btn btn-success btn-sm" onClick={()=>{
                        const newName=editCustomAdminName.trim(); if(!newName) return;
                        const updMenu=items.map(i=>i.id===item.id?{...i,name:newName}:i);
                        saveItems(updMenu);
                        const newOrders={...appState.orders};
                        Object.keys(newOrders).filter(k=>k.startsWith(date+":")).forEach(k=>{
                          const ord=newOrders[k];
                          if(ord&&ord.items.find(i=>i.id===item.id))
                            newOrders[k]={...ord,items:ord.items.map(i=>i.id===item.id?{...i,name:newName}:i)};
                        });
                        update({orders:newOrders});
                        setEditCustomAdmin(null);
                      }}>✓</button>
                      <button className="btn btn-ghost btn-sm" onClick={()=>setEditCustomAdmin(null)}>✕</button>
                    </div>
                  : <div className="flex" style={{alignItems:"center",gap:6}}>
                      <div>
                        <span style={{fontWeight:700}}>{item.name}</span>
                        <div style={{fontSize:".75rem",color:"var(--muted)"}}>Richiesto da: {item.requestedBy}</div>
                      </div>
                      <button className="btn btn-ghost btn-xs" onClick={()=>{setEditCustomAdmin(item.id);setEditCustomAdminName(item.name);}}
                        style={{fontSize:".7rem",padding:"2px 6px"}}>✏️</button>
                    </div>
                }
              </div>
              <div className="flex">
                <span className="muted" style={{fontSize:".82rem"}}>€</span>
                <input style={{width:78,textAlign:"right",padding:"6px 7px"}} type="number" step="0.50" min="0" placeholder="— da inserire"
                  value={item.price??""} onChange={e=>updatePrice(item.id,e.target.value)}/>
                <button className="btn btn-success btn-sm" onClick={()=>{
                  // Salva prezzo nel menu
                  // Aggiorna prezzo e imposta categoria richieste per piatti custom
                  const updatedMenuItems = items.map(i=>i.id===item.id?{...i,price:parseFloat(item.price)||0,categoria:i.custom?"richieste":i.categoria}:i);
                  saveItems(updatedMenuItems);
                  // Aggiorna tutti gli ordini che contengono questo piatto
                  const newOrders={...appState.orders};
                  const newCredits={...appState.credits};
                  // Step 1: ripristina il credito originale di ogni utente coinvolto
                  const utentiCoinvolti=new Set();
                  Object.keys(newOrders).filter(k=>k.startsWith(date+":")).forEach(k=>{
                    const ord=newOrders[k];
                    if(ord&&ord.items.find(i=>i.id===item.id)) utentiCoinvolti.add(ord.userId);
                  });
                  utentiCoinvolti.forEach(uid=>{
                    // Somma tutto il creditUsed degli ordini non pagati di questo utente oggi
                    const creditoUsatoOggi=Object.keys(newOrders)
                      .filter(k=>k.startsWith(date+":"))
                      .reduce((s,k)=>{
                        const o=newOrders[k];
                        return (o&&o.userId===uid)?s+(o.creditUsed||0):s;
                      },0);
                    newCredits[uid]=r2((appState.credits[uid]||0)+creditoUsatoOggi);
                  });
                  // Step 2: ricalcola ogni ordine con il credito originale ripristinato
                  Object.keys(newOrders).filter(k=>k.startsWith(date+":")).forEach(k=>{
                    const ord=newOrders[k];
                    if(!ord||!ord.items.find(i=>i.id===item.id)) return;
                    const price=parseFloat(item.price)||0;
                    const updItems=ord.items.map(i=>i.id===item.id?{...i,price,categoria:"richieste",custom:true}:i);
                    const raw=updItems.reduce((s,i)=>s+(i.price||0)*i.qty,0);
                    const crDisp=newCredits[ord.userId]||0;
                    const cu=crDisp>0?Math.min(crDisp,raw):0;
                    newCredits[ord.userId]=r2(crDisp-cu);
                    const nuovoTot=Math.max(0,raw-cu);
                    const tuttiPrezzati=updItems.every(i=>i.price!=null);
                    const pagato=tuttiPrezzati&&nuovoTot===0;
                    newOrders[k]={...ord,items:updItems,rawTotal:raw,creditUsed:cu,total:nuovoTot,paid:pagato};
                  });
                  Object.keys(newOrders).filter(k=>k.startsWith(date+":")).forEach(k=>{
                    const ordNotif=newOrders[k];
                    if(ordNotif&&ordNotif.items.find(i=>i.id===item.id)){
                      const tok=(appState.fcmTokens||{})[ordNotif.userId];
                      if(tok) sendPush("💰 Prezzo aggiornato", `Il prezzo del tuo ordine. Il tuo ordine: ${eur(ordNotif.total)} da pagare.`, [tok]);
                    }
                  });
                  update({orders:newOrders,credits:newCredits});
                  showToast("✓ Prezzo applicato a tutti gli ordini!");
                }}>✓</button>
                <button className="btn btn-sm" style={{background:"#fdf0ee",color:"var(--red)",border:"1px solid #f0b9b4"}}
                  onClick={()=>saveItems(items.filter(i=>i.id!==item.id))}>✕</button>
              </div>
            </div>
          ))}
        </>
      )}

      <hr className="divider"/>
      <div style={{marginBottom:10,display:"flex",flexDirection:"column",gap:7}}>
        <div className="flex" style={{gap:7}}>
          <select value={newCategoria} onChange={e=>setNewCategoria(e.target.value)}
            style={{flex:"0 0 180px",padding:"7px 10px",borderRadius:8,border:"1px solid var(--border)",background:"var(--surface)"}}>
            {CATEGORIE.map(c=><option key={c.id} value={c.id}>{c.label}</option>)}
          </select>
          <input placeholder="Nome piatto" value={newName} onChange={e=>setNewName(e.target.value)}
            onKeyDown={e=>e.key==="Enter"&&add()} style={{flex:1}}/>
        </div>
        <div className="flex" style={{gap:7}}>
          <input placeholder="€ Prezzo (opzionale)" type="number" step="0.50" min="0"
            value={newPrice} onChange={e=>setNewPrice(e.target.value)} style={{flex:1}}/>
          <button className="btn btn-primary btn-sm" onClick={add}>+ Aggiungi</button>
        </div>
      </div>
      <div className="flex" style={{justifyContent:"space-between",flexWrap:"wrap",gap:8}}>
        <button className="btn btn-gold btn-sm" onClick={duplicatePrev}>📋 Duplica menù di ieri</button>
        <div className="flex" style={{gap:7,flexWrap:"wrap"}}>
          {published
            ?<button className="btn btn-ghost btn-sm" onClick={unpublish}>Nascondi</button>
            :<button className="btn btn-success" onClick={publish} disabled={items.length===0}>📢 Pubblica ai clienti</button>
          }
          {published && (()=>{
            const isOpen = localOrdersOpen !== null
              ? localOrdersOpen
              : isOrdersOpen(date, appState);
            return isOpen
              ? <button className="btn btn-danger btn-sm" onClick={closeOrders}>🔒 Chiudi ordini</button>
              : <button className="btn btn-gold btn-sm" onClick={openOrders}>🔓 Riapri ordini</button>;
          })()}
        </div>
      </div>
      {toast.text&&<div className={`toast ${!toast.ok?"toast-err":""}`}>{toast.text}</div>}
    </div>
  );
}

// ════════════════════════════════════════════════════════════════════════════
// ADMIN – ORDINI
// ════════════════════════════════════════════════════════════════════════════
function AdminOrders({ date, appState, update }) {
  const [editing,    setEditing]    = useState({});
  const [toast,      setToast]      = useState({text:"",err:false});
  const [showAddOrder,setShowAddOrder] = useState(false);
  const [editingOrder,setEditingOrder] = useState(null); // ordine in modifica
  const [editQty,     setEditQty]      = useState({});
  const [editItemNotes,setEditItemNotes]= useState({});
  const [editItemSuppl,setEditItemSuppl]= useState({});
  const [editNote,    setEditNote]     = useState("");
  const [editCustomName,setEditCustomName]=useState("");
  const [editCustomPrice,setEditCustomPrice]=useState("");
  const [addOrderUser,setAddOrderUser] = useState("");
  const [addOrderItems,setAddOrderItems] = useState({}); // {itemId: qty}
  const [addOrderNote,    setAddOrderNote]    = useState("");
  const [addCustomName,   setAddCustomName]   = useState("");
  const [addCustomPrice,  setAddCustomPrice]  = useState("");
  const [addItemNotes,    setAddItemNotes]    = useState({}); // {itemId: nota}
  const [addItemSuppl,    setAddItemSuppl]    = useState({}); // {itemId: supplemento €}
  const showToast=(t,e=false)=>{setToast({text:t,err:e});setTimeout(()=>setToast({text:"",err:false}),2500);};

  const orders = Object.entries(appState.orders)
    .filter(([k])=>k.startsWith(date+":"))
    .map(([,v])=>v).filter(Boolean)
    .sort((a,b)=>a.userName.localeCompare(b.userName));

  const togglePaid = order=>{
    const nowPaid = !order.paid;
    const updated = {...order, paid:nowPaid};
    // Il credito non va mai restituito quando si segna pagato/non pagato
    // Il creditUsed è già stato scalato al momento dell'ordine
    // Non tocchiamo i crediti qui
    update({orders:{...appState.orders,[`${date}:${order.userId}`]:updated}});
    showToast(nowPaid?`✓ ${order.userName} segnato pagato`:`${order.userName} segnato non pagato`);
  };

  const cancelOrderAdmin=(order)=>{
    if(!window.confirm(`Annullare l'ordine di ${order.userName}?`)) return;
    // Restituisci credito se usato
    const newCredits={...appState.credits};
    if(order.creditUsed>0){
      newCredits[order.userId]=r2((newCredits[order.userId]||0)+order.creditUsed);
    }
    const newOrders={...appState.orders};
    delete newOrders[`${date}:${order.userId}`];
    const patchAdmin={orders:newOrders,credits:newCredits};
    update(patchAdmin);
    showToast(`Ordine di ${order.userName} annullato`);
  };

  const openEditOrder=(order)=>{
    setEditingOrder(order);
    const qty={};
    const notes={};
    const suppl={};
    order.items.forEach(i=>{
      qty[i.id]=i.qty;
      if(i.note) notes[i.id]=i.note;
      if(i.supplemento) suppl[i.id]=i.supplemento;
    });
    setEditQty(qty);
    setEditItemNotes(notes);
    setEditItemSuppl(suppl);
    setEditNote(order.note||"");
    setEditCustomName(""); setEditCustomPrice("");
  };

  const saveEditedOrder=()=>{
    const menu = appState.menus[date]||[];
    const items = menu.filter(i=>!i.custom&&(editQty[i.id]||0)>0).map(i=>({
      ...i,
      qty:editQty[i.id],
      note:(editItemNotes[i.id]||"").trim()||undefined,
      supplemento:parseFloat(editItemSuppl[i.id])||0,
      price:(i.price||0)+(parseFloat(editItemSuppl[i.id])||0),
    }));
    // Mantieni i piatti custom originali che non sono nel menù
    editingOrder.items.filter(i=>i.custom).forEach(i=>{
      if((editQty[i.id]||0)>0) items.push({...i,qty:editQty[i.id]});
    });
    // Nuovo piatto custom
    if(editCustomName.trim()){
      items.push({id:"custom_"+Date.now(),name:editCustomName.trim(),price:parseFloat(editCustomPrice)||0,qty:1,custom:true});
    }
    if(!items.length) return showToast("Aggiungi almeno un piatto",true);
    const rawTotal=items.reduce((s,i)=>s+(i.price||0)*i.qty,0);
    // Ripristina credito originale = credito attuale + quello già usato nell'ordine
    const crOriginale=r2((appState.credits[editingOrder.userId]||0)+(editingOrder.creditUsed||0));
    const creditUsed=crOriginale>0?Math.min(crOriginale,rawTotal):0;
    const newCr=r2(crOriginale-creditUsed);
    const nuovoTotal=Math.max(0,rawTotal-creditUsed);
    const hasUnpriced=items.some(i=>i.price==null||i.price===0);
    const pagato=!hasUnpriced&&nuovoTotal===0;
    const updated={...editingOrder,items,rawTotal,creditUsed,total:nuovoTotal,paid:pagato,note:editNote.trim()};
    const newCredits={...appState.credits,[editingOrder.userId]:newCr};
    update({orders:{...appState.orders,[`${date}:${editingOrder.userId}`]:updated},credits:newCredits});
    const pushTokEdit = (appState.fcmTokens||{})[editingOrder.userId];
    if(pushTokEdit) sendPush("✏️ Ordine modificato", `Il tuo ordine è stato modificato. Da pagare: ${eur(nuovoTotal)}`, [pushTokEdit]);
    setEditingOrder(null);
    showToast(`✓ Ordine di ${editingOrder.userName} aggiornato`);
  };

  const addManualOrder=()=>{
    if(!addOrderUser) return showToast("Seleziona un cliente",true);
    const menu = appState.menus[date]||[];
    // Piatti standard con note e supplementi
    const items = menu.filter(i=>!i.custom&&(addOrderItems[i.id]||0)>0)
      .map(i=>({
        ...i,
        qty:addOrderItems[i.id],
        note:(addItemNotes[i.id]||"").trim()||undefined,
        price:(i.price||0)+(parseFloat(addItemSuppl[i.id])||0),
        supplemento:parseFloat(addItemSuppl[i.id])||0,
      }));
    // Piatto personalizzato
    if(addCustomName.trim()){
      items.push({
        id:"custom_"+Date.now(),
        name:addCustomName.trim(),
        price:parseFloat(addCustomPrice)||0,
        qty:1, custom:true,
      });
    }
    if(!items.length) return showToast("Aggiungi almeno un piatto",true);
    const user = appState.users.find(u=>u.id===addOrderUser);
    const rawTotal = items.reduce((s,i)=>s+(i.price||0)*i.qty,0);
    const cr = appState.credits[addOrderUser]||0;
    const creditUsed = cr>0?Math.min(cr,rawTotal):0;
    const netTotal = Math.max(0,rawTotal-creditUsed);
    const newCredits = {...appState.credits,[addOrderUser]:r2(cr-creditUsed)};
    const order = {
      userId:addOrderUser, userName:user.name, date,
      items, rawTotal, creditUsed, total:netTotal,
      paid:false, note:addOrderNote.trim(),
      createdAt:new Date().toISOString(), manualAdmin:true
    };
    update({orders:{...appState.orders,[`${date}:${addOrderUser}`]:order},credits:newCredits});
    const pushTokManual = (appState.fcmTokens||{})[addOrderUser];
    if(pushTokManual) sendPush("📋 Ordine aggiunto", `Il tuo ordine è stato aggiunto. Da pagare: ${eur(netTotal)}`, [pushTokManual]);
    setShowAddOrder(false);
    setAddOrderItems({}); setAddOrderNote(""); setAddOrderUser("");
    setAddCustomName(""); setAddCustomPrice("");
    setAddItemNotes({}); setAddItemSuppl({});
    showToast(`✓ Ordine aggiunto per ${user.name}`);
  };

  const applyItemPrice=(order,itemId)=>{
    const eKey=`${order.userId}_${itemId}`;
    const val=editing[eKey]; if(!val) return;
    const price=parseFloat(val); if(isNaN(price)) return;
    const updatedItems=order.items.map(i=>i.id===itemId?{...i,price}:i);
    const rawTotal=updatedItems.reduce((s,i)=>s+(i.price||0)*i.qty,0);
    // Credito originale = credito attuale + quello già usato nell'ordine
    const crOriginale=r2((appState.credits[order.userId]||0)+(order.creditUsed||0));
    const creditUsed=crOriginale>0?Math.min(crOriginale,rawTotal):0;
    const netTotal=Math.max(0,rawTotal-creditUsed);
    const newCredits={...appState.credits,[order.userId]:r2(crOriginale-creditUsed)};
    const tuttiPrezzati=updatedItems.every(i=>i.price!=null);
    const pagato=tuttiPrezzati&&netTotal===0;
    const updated={...order,items:updatedItems,rawTotal,creditUsed,total:netTotal,paid:pagato};
    update({orders:{...appState.orders,[`${date}:${order.userId}`]:updated},credits:newCredits});
    // Notifica push al cliente
    const pushTokPrice = (appState.fcmTokens||{})[order.userId];
    if(pushTokPrice) sendPush("💰 Prezzo aggiornato", `Ordine aggiornato. Da pagare: ${eur(netTotal)}`, [pushTokPrice]);
    setEditing(p=>{const n={...p};delete n[eKey];return n;});
    showToast("✓ Prezzo aggiornato");

    // Also update menu item price if it was a custom dish
    const menuItems=appState.menus[date]||[];
    const menuItem=menuItems.find(m=>m.id===itemId);
    if(menuItem&&menuItem.custom){
      update({menus:{...appState.menus,[date]:menuItems.map(m=>m.id===itemId?{...m,price}:m)}});
    }
  };

  const totalGiorno  = orders.reduce((s,o)=>s+(o.rawTotal||o.total||0),0);
  const totalIncassato = orders.reduce((s,o)=>s+(o.creditUsed||0),0) // credito usato
                       + orders.filter(o=>o.paid).reduce((s,o)=>s+(o.total||0),0); // cash pagato
  const totalDare    = orders.filter(o=>!o.paid).reduce((s,o)=>s+(o.total||0),0);
  const totalPagato  = totalIncassato;

  return (<>
    <div className="grid3" style={{marginBottom:12}}>
      <div className="stat-box"><div className="stat-num">{eur(totalGiorno)}</div><div className="stat-label">Totale giornata</div></div>
      <div className="stat-box"><div className="stat-num" style={{color:"var(--green)"}}>{eur(totalIncassato)}</div><div className="stat-label">Incassato</div></div>
      <div className="stat-box"><div className="stat-num" style={{color:"var(--red)"}}>{eur(totalDare)}</div><div className="stat-label">Da incassare</div></div>
    </div>
    <div className="card">
      <div className="card-title">🧾 Ordini — {fmt(date)} <span className="badge" style={{background:"var(--accent)"}}>{orders.length}</span></div>
      {/* Modal modifica ordine */}
      {editingOrder&&(()=>{
        const menu=(appState.menus[date]||[]).filter(i=>!i.custom);
        const customOriginals=editingOrder.items.filter(i=>i.custom);
        return(
          <div className="card" style={{marginBottom:14,border:"2px solid var(--accent)",background:"rgba(139,26,26,.03)"}}>
            <div className="card-title" style={{justifyContent:"space-between"}}>
              <span>✏️ Modifica ordine — {editingOrder.userName}</span>
              <button className="btn btn-ghost btn-sm" onClick={()=>setEditingOrder(null)}>✕</button>
            </div>

            {/* Piatti per categoria */}
            {CATEGORIE.map(cat=>{
              const catItems=menu.filter(i=>i.categoria===cat.id||(!i.categoria&&cat.id==="primi"));
              if(!catItems.length) return null;
              return(<div key={cat.id} style={{marginBottom:8}}>
                <div style={{fontSize:".72rem",fontWeight:700,color:"var(--accent)",marginBottom:4,textTransform:"uppercase"}}>{cat.label}</div>
                {catItems.map(item=>(
                  <div key={item.id} style={{marginBottom:6}}>
                    <div className="flex" style={{justifyContent:"space-between"}}>
                      <span style={{fontSize:".85rem"}}>{item.name} {item.price!=null?`(${eur(item.price)})`:"(TBD)"}</span>
                      <div className="qty-ctrl" style={{gap:6}}>
                        <button className="qty-btn" onClick={()=>setEditQty(p=>({...p,[item.id]:Math.max(0,(p[item.id]||0)-1)}))}>−</button>
                        <span className="qty-num" style={{minWidth:20,textAlign:"center"}}>{editQty[item.id]||0}</span>
                        <button className="qty-btn" onClick={()=>setEditQty(p=>({...p,[item.id]:(p[item.id]||0)+1}))}>+</button>
                      </div>
                    </div>
                    {(editQty[item.id]||0)>0&&(
                      <div className="flex" style={{gap:6,marginTop:3}}>
                        <input placeholder="📝 Nota..." value={editItemNotes[item.id]||""}
                          onChange={e=>setEditItemNotes(p=>({...p,[item.id]:e.target.value}))}
                          style={{flex:1,fontSize:".78rem"}}/>
                        <input placeholder="+ €" type="number" step="0.50" min="0"
                          value={editItemSuppl[item.id]||""}
                          onChange={e=>setEditItemSuppl(p=>({...p,[item.id]:e.target.value}))}
                          style={{width:60,fontSize:".78rem",textAlign:"right"}}/>
                      </div>
                    )}
                  </div>
                ))}
              </div>);
            })}

            {/* Piatti custom originali */}
            {customOriginals.length>0&&<div style={{marginBottom:8}}>
              <div style={{fontSize:".72rem",fontWeight:700,color:"var(--gold)",marginBottom:4,textTransform:"uppercase"}}>⭐ Piatti personalizzati</div>
              {customOriginals.map(item=>(
                <div key={item.id} className="flex" style={{justifyContent:"space-between",marginBottom:4}}>
                  <span style={{fontSize:".85rem"}}>{item.name} ({eur(item.price)})</span>
                  <div className="qty-ctrl" style={{gap:6}}>
                    <button className="qty-btn" onClick={()=>setEditQty(p=>({...p,[item.id]:Math.max(0,(p[item.id]||0)-1)}))}>−</button>
                    <span className="qty-num" style={{minWidth:20,textAlign:"center"}}>{editQty[item.id]??item.qty}</span>
                    <button className="qty-btn" onClick={()=>setEditQty(p=>({...p,[item.id]:(p[item.id]??item.qty)+1}))}>+</button>
                  </div>
                </div>
              ))}
            </div>}

            {/* Nuovo piatto custom */}
            <div style={{background:"rgba(200,148,42,.08)",borderRadius:8,padding:"10px",marginBottom:10,border:"1px solid #f5d78e"}}>
              <div style={{fontSize:".72rem",fontWeight:700,color:"var(--gold)",marginBottom:5,textTransform:"uppercase"}}>+ Aggiungi piatto</div>
              <div className="flex" style={{gap:6}}>
                <input placeholder="Nome piatto..." value={editCustomName}
                  onChange={e=>setEditCustomName(e.target.value)} style={{flex:1,fontSize:".85rem"}}/>
                <input placeholder="€" type="number" step="0.50" min="0"
                  value={editCustomPrice} onChange={e=>setEditCustomPrice(e.target.value)}
                  style={{width:70,fontSize:".85rem",textAlign:"right"}}/>
              </div>
            </div>

            <div className="field" style={{marginBottom:10}}>
              <label>Note generali</label>
              <input value={editNote} onChange={e=>setEditNote(e.target.value)} placeholder="Note ordine..."/>
            </div>

            <button className="btn btn-primary" onClick={saveEditedOrder}>💾 Salva modifiche</button>
          </div>
        );
      })()}

      {/* Bottone aggiungi ordine manuale */}
      <div style={{marginBottom:12}}>
        <button className="btn btn-gold btn-sm" onClick={()=>setShowAddOrder(!showAddOrder)}>
          {showAddOrder?"✕ Annulla":"+ Aggiungi ordine manuale"}
        </button>
      </div>

      {showAddOrder&&(()=>{
        const menu = (appState.menus[date]||[]).filter(i=>!i.custom);
        const clients = appState.users.filter(u=>u.role!=="admin"&&u.approved);
        return(
          <div className="card" style={{marginBottom:14,background:"var(--gold-lt)",border:"1px solid #f5d78e"}}>
            <div className="card-title">📝 Nuovo ordine manuale</div>
            <div className="field" style={{marginBottom:8}}>
              <label>Cliente</label>
              <select value={addOrderUser} onChange={e=>setAddOrderUser(e.target.value)}
                style={{padding:"7px 10px",borderRadius:8,border:"1px solid var(--border)",background:"var(--surface)",width:"100%"}}>
                <option value="">— Seleziona cliente —</option>
                {clients.map(c=><option key={c.id} value={c.id}>{c.name}</option>)}
              </select>
            </div>
            <div style={{marginBottom:8}}>
              <label style={{fontSize:".78rem",fontWeight:700,color:"var(--muted)",display:"block",marginBottom:4}}>Piatti</label>
              {CATEGORIE.map(cat=>{
                const catItems = menu.filter(i=>i.categoria===cat.id||(!i.categoria&&cat.id==="primi"));
                if(!catItems.length) return null;
                return(<div key={cat.id} style={{marginBottom:6}}>
                  <div style={{fontSize:".72rem",fontWeight:700,color:"var(--accent)",marginBottom:3}}>{cat.label}</div>
                  {catItems.map(item=>(
                    <div key={item.id} style={{marginBottom:8}}>
                      <div className="flex" style={{justifyContent:"space-between"}}>
                        <span style={{fontSize:".85rem",fontWeight:500}}>{item.name} {item.price!=null?`(${eur(item.price)})`:"(TBD)"}</span>
                        <div className="qty-ctrl" style={{gap:6}}>
                          <button className="qty-btn" onClick={()=>setAddOrderItems(p=>({...p,[item.id]:Math.max(0,(p[item.id]||0)-1)}))}>−</button>
                          <span className="qty-num" style={{minWidth:20,textAlign:"center"}}>{addOrderItems[item.id]||0}</span>
                          <button className="qty-btn" onClick={()=>setAddOrderItems(p=>({...p,[item.id]:(p[item.id]||0)+1}))}>+</button>
                        </div>
                      </div>
                      {(addOrderItems[item.id]||0)>0&&(
                        <div className="flex" style={{gap:6,marginTop:4}}>
                          <input
                            placeholder="📝 Nota (es. abbondante)..."
                            value={addItemNotes[item.id]||""}
                            onChange={e=>setAddItemNotes(p=>({...p,[item.id]:e.target.value}))}
                            style={{flex:1,fontSize:".78rem"}}
                          />
                          <input
                            placeholder="+ €"
                            type="number" step="0.50" min="0"
                            value={addItemSuppl[item.id]||""}
                            onChange={e=>setAddItemSuppl(p=>({...p,[item.id]:e.target.value}))}
                            style={{width:60,fontSize:".78rem",textAlign:"right"}}
                          />
                        </div>
                      )}
                    </div>
                  ))}
                </div>);
              })}
            </div>
            {/* Piatto personalizzato */}
            <div style={{background:"rgba(200,148,42,.08)",borderRadius:8,padding:"10px",marginBottom:10,border:"1px solid #f5d78e"}}>
              <div style={{fontSize:".75rem",fontWeight:700,color:"var(--gold)",marginBottom:6,textTransform:"uppercase"}}>⭐ Piatto personalizzato</div>
              <div className="flex" style={{gap:6}}>
                <input
                  placeholder="Nome piatto custom..."
                  value={addCustomName} onChange={e=>setAddCustomName(e.target.value)}
                  style={{flex:1,fontSize:".85rem"}}
                />
                <input
                  placeholder="€ Prezzo"
                  type="number" step="0.50" min="0"
                  value={addCustomPrice} onChange={e=>setAddCustomPrice(e.target.value)}
                  style={{width:80,fontSize:".85rem",textAlign:"right"}}
                />
              </div>
            </div>
            <div className="field" style={{marginBottom:10}}>
              <label>Note generali ordine (opzionale)</label>
              <input value={addOrderNote} onChange={e=>setAddOrderNote(e.target.value)} placeholder="Note generali..."/>
            </div>
            <button className="btn btn-primary" onClick={addManualOrder}>✓ Conferma ordine</button>
          </div>
        );
      })()}

      {orders.length===0&&<div className="empty">Nessun ordine per questa data.</div>}
      {orders.map(order=>{
        const cr=appState.credits[order.userId]||0;
        return(
          <div className="order-block" key={order.userId}>
            <div className="flex" style={{justifyContent:"space-between",marginBottom:7,flexWrap:"wrap",gap:5}}>
              <span style={{fontWeight:700}}>👤 {order.userName}</span>
              <div className="flex" style={{flexWrap:"wrap",gap:5}}>
                {cr>0&&<span className="credit-pill credit-pos">💳 {eur(cr)}</span>}
                <span style={{fontWeight:800,color:"var(--accent)"}}>{eur(order.total)}</span>
                <div className="flex" style={{gap:6}}>
                  <span className={`paid-badge ${order.paid?"pagato":"non-pagato"}`} onClick={()=>togglePaid(order)}>
                    {order.paid?"✓ Pagato":"✗ Non pagato"}
                  </span>
                  <button className="btn btn-ghost btn-xs" onClick={()=>openEditOrder(order)}>✏️ Modifica</button>
                  <button className="btn btn-danger btn-xs" onClick={()=>cancelOrderAdmin(order)}>🗑 Annulla</button>
                </div>
              </div>
            </div>
            {order.note&&<div style={{fontSize:".8rem",color:"var(--text2)",marginBottom:6,background:"var(--gold-lt)",padding:"5px 10px",borderRadius:7,border:"1px solid #f5d78e"}}>📝 <b>Nota:</b> {order.note}</div>}
            {(order.creditUsed||0)>0&&<div style={{fontSize:".75rem",color:"var(--green)",marginBottom:6,fontWeight:700}}>✓ Credito scalato: −{eur(order.creditUsed)} · Netto: {eur(order.total)}</div>}
            {order.items.map(item=>{
              const eKey=`${order.userId}_${item.id}`;
              return(
                <div className="order-row" key={item.id}>
                  <span style={{flex:1,fontSize:".85rem",fontWeight:item.custom?700:500}}>
                    {item.custom&&"⭐ "}{item.name}
                    {item.note&&<div style={{marginTop:3}}>
                      <div style={{fontSize:".75rem",color:"var(--muted)",fontStyle:"italic"}}>📝 {item.note}</div>
                      <div className="flex" style={{gap:5,marginTop:3,alignItems:"center"}}>
                        <span style={{fontSize:".7rem",color:"var(--muted)"}}>+ Suppl. €</span>
                        <input type="number" step="0.50" min="0" placeholder="0.00"
                          style={{width:65,padding:"3px 6px",fontSize:".75rem",textAlign:"right"}}
                          value={editing[`supp_${item.id}`]??((item.supplemento||0)>0?item.supplemento:"")}
                          onChange={e=>setEditing(p=>({...p,[`supp_${item.id}`]:e.target.value}))}
                          onKeyDown={e=>{
                            if(e.key==="Enter"){
                              const val=parseFloat(editing[`supp_${item.id}`])||0;
                              const updItems=order.items.map(i=>i.id===item.id?{...i,supplemento:val,price:(i.price||0)+(val-(i.supplemento||0))}:i);
                              const raw=updItems.reduce((s,i)=>s+(i.price||0)*i.qty,0);
                              // Ripristina credito originale prima di ricalcolare
                              const crOrig=r2((appState.credits[order.userId]||0)+(order.creditUsed||0));
                              const cu=crOrig>0?Math.min(crOrig,raw):0;
                              const nuovoTot=Math.max(0,raw-cu);
                              const tuttiPrezzati=updItems.every(i=>i.price!=null);
                              const pagato=tuttiPrezzati&&nuovoTot===0&&cu>0;
                              const newCr=r2(crOrig-cu);
                              const updated={...order,items:updItems,rawTotal:raw,creditUsed:cu,total:nuovoTot,paid:pagato};
                              update({orders:{...appState.orders,[`${date}:${order.userId}`]:updated},credits:{...appState.credits,[order.userId]:newCr}});
                              setEditing(p=>{const n={...p};delete n[`supp_${item.id}`];return n;});
                              showToast("✓ Supplemento aggiunto");
                            }
                          }}
                        />
                        <span style={{fontSize:".7rem",color:"var(--muted)"}}>Invio ↵</span>
                        {(item.supplemento||0)>0&&<span style={{color:"var(--gold)",fontWeight:700,fontSize:".78rem"}}>+{eur(item.supplemento)}</span>}
                      </div>
                    </div>}
                  </span>
                  <span className="muted" style={{minWidth:24}}>×{item.qty}</span>
                  {item.price!=null
                    ?<span style={{color:"var(--accent)",fontWeight:700,minWidth:60,textAlign:"right",fontSize:".85rem"}}>
                      {item.supplemento>0
                        ? <span>{eur((item.price-item.supplemento)*item.qty)}<span style={{color:"var(--gold)",fontSize:".75rem"}}> +{eur(item.supplemento*item.qty)}</span> = {eur(item.price*item.qty)}</span>
                        : eur(item.price*item.qty)
                      }
                    </span>
                    :<div className="flex" style={{gap:4}}>
                      <span className="muted" style={{fontSize:".73rem"}}>€</span>
                      <input type="number" step="0.50" min="0" placeholder="—" style={{width:70,padding:"4px 6px",fontSize:".8rem"}}
                        value={editing[eKey]??""} onChange={e=>setEditing(p=>({...p,[eKey]:e.target.value}))}
                        onBlur={()=>applyItemPrice(order,item.id)} onKeyDown={e=>e.key==="Enter"&&applyItemPrice(order,item.id)}/>
                    </div>
                  }
                </div>
              );
            })}
            {order.items.some(i=>i.price==null)&&<div style={{fontSize:".73rem",color:"var(--yellow)",marginTop:5,fontWeight:700}}>⚠ Prezzi da completare</div>}
          </div>
        );
      })}
    </div>
    {toast.text&&<div className={`toast ${toast.err?"toast-err":""}`}>{toast.text}</div>}
  </>);
}

// ════════════════════════════════════════════════════════════════════════════
// ADMIN – NOTIFICHE
// ════════════════════════════════════════════════════════════════════════════
function AdminNotifications({ appState, update }) {
  const [target,  setTarget]  = useState("all");
  const [message, setMessage] = useState("");
  const [toast,   setToast]   = useState({text:"",err:false});
  const showToast=(t,e=false)=>{setToast({text:t,err:e});setTimeout(()=>setToast({text:"",err:false}),2500);};
  const clients=appState.users.filter(u=>u.role==="client"&&u.approved);

  const send=()=>{
    if(!message.trim()) return showToast("Scrivi un messaggio",true);
    const targets=target==="all"?clients:clients.filter(u=>u.id===target);
    if(!targets.length) return showToast("Nessun destinatario",true);
    setMessage(""); // pulisci subito per evitare doppio invio
    const newNotifs={...appState.notifications};
    const now = new Date().toISOString();
    for(const c of targets){
      const prev=newNotifs[c.id]||[];
      newNotifs[c.id]=[{id:Date.now().toString()+c.id,text:message.trim(),date:now,read:false},...prev].slice(0,50);
    }
    const record={id:Date.now().toString(),text:message.trim(),to:target==="all"?"Tutti":targets[0].name,date:now};
    const patch={notifications:newNotifs,sentNotifs:[record,...(appState.sentNotifs||[])].slice(0,30)};
    update(patch);
    // Invia anche push reale via OneSignal
    // Raccoglie i token FCM solo dei destinatari selezionati
    const fcmTokens = appState.fcmTokens||{};
    const pushTokens = targets.map(c=>fcmTokens[c.id]).filter(Boolean);
    if(pushTokens.length>0) sendPush("📢 Dolci Sapori", message.trim(), pushTokens);
    else if(target==="all") {
      // Fallback: tutti i token tranne admin
      const allTokens = appState.users
        .filter(u=>u.role!=="admin"&&u.approved)
        .map(u=>fcmTokens[u.id]).filter(Boolean);
      if(allTokens.length>0) sendPush("📢 Dolci Sapori", message.trim(), allTokens);
    }
    showToast(`✓ Notifica inviata a ${record.to}`);
  };

  return(<>
    <div className="card">
      <div className="card-title">🔔 Invia notifica</div>
      <div className="field"><label>Destinatario</label>
        <select value={target} onChange={e=>setTarget(e.target.value)}>
          <option value="all">📢 Tutti i clienti</option>
          {clients.map(u=><option key={u.id} value={u.id}>👤 {u.name}</option>)}
        </select>
      </div>
      <div className="field"><label>Messaggio</label>
        <textarea value={message} onChange={e=>setMessage(e.target.value)} placeholder="Es: Il menù di oggi è pronto! 🍝" style={{minHeight:80}}/>
      </div>
      <button className="btn btn-primary" onClick={send}>📨 Invia notifica</button>
    </div>
    <div className="card">
      <div className="card-title">📤 Inviate di recente</div>
      {(!appState.sentNotifs||!appState.sentNotifs.length)&&<div className="empty">Nessuna notifica inviata.</div>}
      {(appState.sentNotifs||[]).map(n=>(
        <div key={n.id} style={{borderBottom:"1px solid var(--border)",padding:"8px 0"}}>
          <div className="flex" style={{justifyContent:"space-between",marginBottom:3}}>
            <span style={{fontWeight:700,fontSize:".86rem"}}>→ {n.to}</span>
            <span className="muted" style={{fontSize:".73rem"}}>{n.date ? new Date(n.date).toLocaleString("it-IT",{day:"numeric",month:"short",hour:"2-digit",minute:"2-digit"}) : ""}</span>
          </div>
          <div style={{fontSize:".85rem"}}>{n.text||n.message||""}</div>
        </div>
      ))}
    </div>
    {toast.text&&<div className={`toast ${toast.err?"toast-err":""}`}>{toast.text}</div>}
  </>);
}

// ════════════════════════════════════════════════════════════════════════════
// ADMIN – CLIENTI + CREDITI
// ════════════════════════════════════════════════════════════════════════════
function AdminClients({ appState, update }) {
  const [newForm,    setNewForm]    = useState({name:"",id:"",password:""});
  const [creditEdit, setCreditEdit] = useState({});
  const [toast,      setToast]      = useState({text:"",err:false});
  const showToast=(t,e=false)=>{setToast({text:t,err:e});setTimeout(()=>setToast({text:"",err:false}),2500);};

  const clients  = appState.users.filter(u=>u.role==="client");
  const pending  = clients.filter(u=>!u.approved);
  const approved = clients.filter(u=>u.approved);

  const approve    = id=>{update({users:appState.users.map(u=>u.id===id?{...u,approved:true}:u)});showToast("✓ Cliente approvato");};
  const removeUser = id=>{if(!window.confirm("Eliminare questo account?"))return;update({users:appState.users.filter(u=>u.id!==id)});showToast("Account eliminato",true);};

  const addClient=()=>{
    const id=newForm.id.trim().toLowerCase().replace(/\s+/g,"");
    if(!id||!newForm.name.trim()||!newForm.password) return showToast("Compila tutti i campi",true);
    if(id.length<3) return showToast("Username troppo corto",true);
    if(appState.users.find(u=>u.id===id)) return showToast("Username già in uso",true);
    update({users:[...appState.users,{id,name:newForm.name.trim(),role:"client",password:newForm.password.trim(),approved:true}]});
    setNewForm({name:"",id:"",password:""}); showToast("✓ Cliente aggiunto");
  };

  const applyCredit=(userId,sign)=>{
    const val=parseFloat(creditEdit[userId]);
    if(isNaN(val)||val<=0) return showToast("Importo non valido",true);
    setCreditEdit(p=>{const n={...p};delete n[userId];return n;});

    // Calcola il credito totale disponibile:
    // credito attuale + creditUsed degli ordini non pagati + nuovo valore aggiunto/tolto
    const newOrders = {...appState.orders};
    const creditoUsatoNonPagato = Object.keys(newOrders).reduce((s,k)=>{
      const o=newOrders[k];
      return (o&&!o.paid&&o.userId===userId)?s+(o.creditUsed||0):s;
    },0);
    const creditoTotale = r2((appState.credits[userId]||0) + creditoUsatoNonPagato + sign*val);
    if(creditoTotale<0) return showToast("Credito insufficiente",true);

    // Ricalcola gli ordini non pagati con il credito totale disponibile
    const newCredits = {...appState.credits};
    let crRimanente = creditoTotale;
    Object.keys(newOrders).forEach(k=>{
      const o = newOrders[k];
      if(!o || o.paid || o.userId!==userId) return;
      const raw = o.rawTotal||o.total||0;
      const cu = crRimanente>0 ? Math.min(crRimanente,raw) : 0;
      crRimanente = r2(crRimanente - cu);
      const nuovoTotal = Math.max(0, raw-cu);
      const hasUnpriced = (o.items||[]).some(i=>i.price==null||i.price===0);
      const autoPaid = nuovoTotal===0 && !hasUnpriced;
      newOrders[k] = {...o, creditUsed:cu, total:nuovoTotal, paid:autoPaid||o.paid};
    });
    newCredits[userId] = crRimanente;

    update({credits:newCredits, orders:newOrders});
    showToast(sign>0?`✓ Credito aggiunto: +${eur(val)}`:`✓ Credito scalato: −${eur(val)}`);
  };
  const resetCr=userId=>{if(!window.confirm("Azzerare il credito?")) return; update({credits:{...appState.credits,[userId]:0}});showToast("Credito azzerato");};
  const [resetPwdUser, setResetPwdUser] = useState(null);
  const [newPwdAdmin,  setNewPwdAdmin]  = useState("");
  const saveResetPwd = () => {
    if(!newPwdAdmin.trim()||newPwdAdmin.length<4) return showToast("Password troppo corta (min 4)",true);
    const updUsers = appState.users.map(u=>u.id===resetPwdUser?{...u,password:newPwdAdmin.trim()}:u);
    update({users:updUsers});
    setResetPwdUser(null); setNewPwdAdmin("");
    showToast("✓ Password aggiornata!");
  };

  return(<>
    {pending.length>0&&(
      <div className="card">
        <div className="card-title">⏳ In attesa di approvazione <span className="badge badge-red">{pending.length}</span></div>
        {pending.map(u=>(
          <div key={u.id} style={{display:"flex",alignItems:"center",gap:9,padding:"9px 0",borderBottom:"1px solid var(--border)",flexWrap:"wrap"}}>
            <div className="avatar">{initials(u.name)}</div>
            <div style={{flex:1}}><div style={{fontWeight:700}}>{u.name}</div><div className="muted">@{u.id}</div></div>
            <span className="pending-badge">⏳ In attesa</span>
            <button className="btn btn-success btn-sm" onClick={()=>approve(u.id)}>✓ Approva</button>
            <button className="btn btn-danger btn-sm"  onClick={()=>removeUser(u.id)}>✕ Rifiuta</button>
          </div>
        ))}
      </div>
    )}

    <div className="card">
      <div className="card-title">➕ Aggiungi cliente manualmente</div>
      <div className="grid3" style={{marginBottom:10}}>
        <div><label>Nome completo</label><input placeholder="Mario Rossi" value={newForm.name} onChange={e=>setNewForm(p=>({...p,name:e.target.value}))}/></div>
        <div><label>Username</label><input placeholder="mario" value={newForm.id} onChange={e=>setNewForm(p=>({...p,id:e.target.value}))}/></div>
        <div><label>Password</label><input placeholder="password" value={newForm.password} onChange={e=>setNewForm(p=>({...p,password:e.target.value}))}/></div>
      </div>
      <button className="btn btn-primary btn-sm" onClick={addClient}>+ Aggiungi cliente</button>
    </div>

    <div className="card">
      <div className="card-title">👥 Clienti attivi ({approved.length})</div>
      {approved.length===0&&<div className="empty">Nessun cliente attivo.</div>}
      {approved.map(u=>{
        const cr   = appState.credits[u.id]||0;
        const debt = getUserDebt(u.id, appState.orders);
        return(
          <div key={u.id} style={{borderBottom:"1px solid var(--border)",paddingBottom:14,marginBottom:14}}>
            <div className="flex" style={{justifyContent:"space-between",marginBottom:9,flexWrap:"wrap",gap:7}}>
              <div className="flex">
                <div className="avatar">{initials(u.name)}</div>
                <div>
                  <div style={{fontWeight:700}}>{u.name}</div>
                  <div className="flex" style={{alignItems:"center",gap:8,flexWrap:"wrap"}}>
                  <span className="muted">@{u.id} · pw: {u.password}</span>
                  <button className="btn btn-ghost btn-xs" onClick={()=>{setResetPwdUser(u.id);setNewPwdAdmin("");}}
                    style={{fontSize:".7rem"}}>🔑 Reset pw</button>
                </div>
                {resetPwdUser===u.id&&(
                  <div className="flex" style={{gap:6,marginTop:6}}>
                    <input type="text" placeholder="Nuova password..."
                      value={newPwdAdmin} onChange={e=>setNewPwdAdmin(e.target.value)}
                      style={{flex:1,fontSize:".82rem"}}
                      onKeyDown={e=>e.key==="Enter"&&saveResetPwd()}
                    />
                    <button className="btn btn-success btn-sm" onClick={saveResetPwd}>✓</button>
                    <button className="btn btn-ghost btn-sm" onClick={()=>setResetPwdUser(null)}>✕</button>
                  </div>
                )}
                </div>
              </div>
              {/* Credit + Debt summary */}
              <div className="flex" style={{gap:6,flexWrap:"wrap"}}>
                {debt>0  && <span className="debt-pill">⚠ Deve dare {eur(debt)}</span>}
                {debt===0 && cr>0 && <span className="credit-pill credit-pos">💳 Credito {eur(cr)}</span>}
                {debt===0 && cr===0 && <span className="credit-pill credit-zero">In pari</span>}
                <button className="btn btn-danger btn-xs" onClick={()=>removeUser(u.id)}>✕</button>
              </div>
            </div>
            {/* Credit controls */}
            <div style={{background:"var(--bg)",borderRadius:9,padding:"10px 12px",border:"1px solid var(--border)"}}>
              <div className="muted" style={{fontSize:".7rem",marginBottom:7,fontWeight:700,textTransform:"uppercase",letterSpacing:".04em"}}>Gestione credito</div>
              <div className="flex" style={{flexWrap:"wrap",gap:7}}>
                <input type="number" step="0.50" min="0.50" placeholder="Importo €"
                  style={{width:118,padding:"6px 8px",fontSize:".8rem"}}
                  value={creditEdit[u.id]??""} onChange={e=>setCreditEdit(p=>({...p,[u.id]:e.target.value}))}/>
                <button className="btn btn-success btn-sm" onClick={()=>applyCredit(u.id,+1)}>+ Aggiungi</button>
                <button className="btn btn-ghost btn-sm"   onClick={()=>applyCredit(u.id,-1)}>− Scala</button>
                {cr>0&&<button className="btn btn-ghost btn-sm" style={{color:"var(--red)",borderColor:"#f0b9b4"}} onClick={()=>resetCr(u.id)}>Azzera</button>}
              </div>
            </div>
          </div>
        );
      })}
    </div>
    {toast.text&&<div className={`toast ${toast.err?"toast-err":""}`}>{toast.text}</div>}
  </>);
}

// ════════════════════════════════════════════════════════════════════════════
// ADMIN – STORICO
// ════════════════════════════════════════════════════════════════════════════
// ════════════════════════════════════════════════════════════════════════════
// ADMIN – RIEPILOGO GIORNALIERO
// ════════════════════════════════════════════════════════════════════════════
function AdminRiepilogo({ date, appState }) {
  const orders = Object.entries(appState.orders||{})
    .filter(([k])=>k.startsWith(date+":"))
    .map(([,v])=>v).filter(Boolean);

  // Raggruppa tutti i piatti ordinati
  // Aggrega per nome + nota (separati) così "2× pasta" e "1× pasta - abbondante" restano distinti
  const piattiMap = {};
  orders.forEach(ord=>{
    ord.items.forEach(item=>{
      const key = item.name + (item.note ? "__" + item.note : "");
      if(!piattiMap[key]) piattiMap[key]={name:item.name, qty:0, custom:item.custom||false, note:item.note||null, categoria:item.categoria||"primi"};
      piattiMap[key].qty += item.qty;
    });
  });
  const lista = Object.values(piattiMap).sort((a,b)=>{
    if(a.name!==b.name) return a.name.localeCompare(b.name);
    return (a.note||"").localeCompare(b.note||"");
  });

  const totaleOrdini  = orders.length;
  const totaleGiornata = orders.reduce((s,o)=>s+(o.rawTotal||o.total||0),0);
  const totaleIncasso  = orders.reduce((s,o)=>s+(o.creditUsed||0),0)
                       + orders.filter(o=>o.paid).reduce((s,o)=>s+(o.total||0),0);
  const totalePagato   = totaleIncasso;
  const daIncassare    = orders.filter(o=>!o.paid).reduce((s,o)=>s+(o.total||0),0);

  // Esporta come testo
  const esporta = ()=>{
    const righe = [
      `RIEPILOGO ORDINI — ${new Date(date+"T12:00:00").toLocaleDateString("it-IT",{weekday:"long",day:"numeric",month:"long",year:"numeric"})}`,
      ``,
      `PIATTI DA PREPARARE:`,
      ...lista.flatMap(p=>Array.from({length:p.qty},()=>`  ${p.name}${p.custom?" (su richiesta)":""}${p.note?" - "+p.note:""}`)),
      ``,
      `ORDINI (${totaleOrdini}):`,
      ...orders.map(o=>[
        `  ${o.userName}: ${eur(o.total)} ${o.paid?"✓":"⏳"}${o.note?` — nota generale: ${o.note}`:""}`,
        ...o.items.filter(i=>i.note).map(i=>`     └ ${i.name}: ${i.note}`)
      ].join("\n")),
      ``,
      `Totale incasso: ${eur(totaleIncasso)}`,
      `Già pagato: ${eur(totalePagato)}`,
      `Da incassare: ${eur(totaleIncasso-totalePagato)}`,
    ];
    const blob = new Blob([righe.join("\n")], {type:"text/plain"});
    const a = document.createElement("a");
    a.href = URL.createObjectURL(blob);
    a.download = `ordini_${date}.txt`;
    a.click();
  };

  return(
    <div>
      <div className="grid3" style={{marginBottom:14}}>
        <div className="stat-box">
          <div className="stat-num">{eur(totaleGiornata)}</div>
          <div className="stat-label">Totale giornata</div>
        </div>
        <div className="stat-box">
          <div className="stat-num">{eur(totaleIncasso)}</div>
          <div className="stat-label">Incassato</div>
        </div>
        <div className="stat-box">
          <div className="stat-num">{eur(daIncassare)}</div>
          <div className="stat-label">Da incassare</div>
        </div>
      </div>

      <div className="card">
        <div className="card-title" style={{justifyContent:"space-between"}}>
          <span>🍽 Piatti da preparare</span>
          <button className="btn btn-gold btn-sm" onClick={esporta}>⬇ Esporta</button>
        </div>
        {lista.length===0
          ? <div className="empty">Nessun ordine per oggi.</div>
          : CATEGORIE.map(cat=>{
              const catPiatti = lista.filter(p=>p.categoria===cat.id||(!p.categoria&&cat.id==="primi"));
              if(!catPiatti.length) return null;
              return(<div key={cat.id} style={{marginBottom:10}}>
                <div style={{fontSize:".72rem",fontWeight:700,color:"var(--accent)",
                  textTransform:"uppercase",letterSpacing:".04em",
                  borderBottom:"1px solid var(--border-lt)",paddingBottom:3,marginBottom:5}}>
                  {cat.label}
                </div>
                {catPiatti.flatMap(p=>Array.from({length:p.qty},(_,i)=>(
                  <div key={p.name+i} className="menu-item" style={{marginBottom:4}}>
                    <span style={{fontWeight:p.custom?700:500}}>
                      {p.custom?"🌟 ":""}{p.name}
                      {p.note&&<span style={{fontSize:".75rem",color:"var(--muted)",fontStyle:"italic",marginLeft:6}}>- {p.note}</span>}
                    </span>
                  </div>
                )))}
              </div>);
            })
        }
      </div>

      <div className="card">
        <div className="card-title">👥 Chi ha ordinato</div>
        {orders.length===0
          ? <div className="empty">Nessun ordine.</div>
          : orders.map(o=>(
              <div key={o.userId} style={{borderBottom:"1px solid var(--border-lt)",padding:"8px 0"}}>
                <div className="flex" style={{justifyContent:"space-between"}}>
                  <span style={{fontWeight:700}}>{o.userName}</span>
                  <div className="flex" style={{gap:6}}>
                    <span style={{fontWeight:700,color:"var(--accent)"}}>{eur(o.total)}</span>
                    <span className={`paid-badge ${o.paid?"pagato":"non-pagato"}`} style={{cursor:"default",fontSize:".68rem"}}>
                      {o.paid?"✓ Pagato":"⏳ Da pagare"}
                    </span>
                  </div>
                </div>
                {o.note&&<div style={{fontSize:".78rem",color:"var(--muted)",marginTop:3,fontStyle:"italic"}}>📝 {o.note}</div>}
                <div style={{fontSize:".8rem",color:"var(--muted)",marginTop:3}}>
                  {o.items.map(i=>`${i.qty}× ${i.name}${i.note?` (${i.note})`:""}`).join(", ")}
                </div>
              </div>
            ))
        }
      </div>
    </div>
  );
}


function AdminSummary({ appState }) {
  const byDate={};
  for(const[k,o]of Object.entries(appState.orders)){
    if(!o)continue; const d=k.split(":")[0];
    if(!byDate[d])byDate[d]=[];byDate[d].push(o);
  }
  const records=Object.entries(byDate).sort((a,b)=>b[0].localeCompare(a[0])).map(([date,orders])=>({
    date,
    total:  orders.reduce((s,o)=>s+(o.total||0),0),
    pagato: orders.filter(o=>o.paid).reduce((s,o)=>s+(o.total||0),0),
    count:  orders.length,
    nonPaganti:orders.filter(o=>!o.paid).map(o=>o.userName),
  }));
  const gt=records.reduce((s,r)=>s+r.total,0);
  const gp=records.reduce((s,r)=>s+r.pagato,0);
  return(
    <div className="card">
      <div className="card-title">📊 Storico</div>
      <div className="grid2" style={{marginBottom:14}}>
        <div className="stat-box"><div className="stat-num">{eur(gt)}</div><div className="stat-label">Totale storico</div></div>
        <div className="stat-box"><div className="stat-num" style={{color:"var(--red)"}}>{eur(gt-gp)}</div><div className="stat-label">Da incassare</div></div>
      </div>
      {records.length===0&&<div className="empty">Nessun dato ancora.</div>}
      {records.map(r=>(
        <div key={r.date} style={{borderBottom:"1px solid var(--border)",padding:"10px 0"}}>
          <div className="flex" style={{justifyContent:"space-between"}}>
            <div><div style={{fontWeight:700}}>{fmtS(r.date)}</div><div className="muted">{r.count} ordini</div></div>
            <div style={{textAlign:"right"}}>
              <div style={{fontWeight:800,color:"var(--accent)"}}>{eur(r.total)}</div>
              <div style={{fontSize:".75rem",color:r.total-r.pagato>0?"var(--red)":"var(--green)",fontWeight:700}}>
                {r.total-r.pagato>0?`Da incassare: ${eur(r.total-r.pagato)}`:"✓ Tutto incassato"}
              </div>
            </div>
          </div>
          {r.nonPaganti.length>0&&<div style={{fontSize:".72rem",color:"var(--red)",marginTop:3}}>Non pagato: {r.nonPaganti.join(", ")}</div>}
        </div>
      ))}
    </div>
  );
}

// ════════════════════════════════════════════════════════════════════════════
// ADMIN ROOT
// ════════════════════════════════════════════════════════════════════════════
function AdminPanel({ user, appState, update, onLogout }) {
  const [tab, setTab]   = useState("menu");
  const [date,setDate]  = useState(today());
  const pendingCount = appState.users.filter(u=>u.role==="client"&&!u.approved).length;

  return(
    <div className="app">
      <div className="header">
        <div className="header-top">
          <div className="header-logo" style={{gap:6}}>
            <LogoIcon size={42}/>
            {!BRAND.logoUrl && BRAND.name}
            <span className="badge">ADMIN</span>
          </div>
          <div className="header-actions">
            <span className="header-user">👤 {user.name}</span>
            <button className="tab" onClick={onLogout} style={{marginLeft:2,padding:"5px 8px"}}>⬅</button>
          </div>
        </div>
        <div className="header-tabs">
          {[["menu","📋 Menù"],["orders","🧾 Ordini"],["riepilogo","📊 Riepilogo"],["notif","🔔 Notifiche"],["clients","👥 Clienti"],["summary","📅 Storico"]].map(([v,l])=>(
            <button key={v} className={`tab ${tab===v?"active":""}`} onClick={()=>setTab(v)}>
              {l}{v==="clients"&&pendingCount>0&&<span className="badge badge-red" style={{marginLeft:3}}>{pendingCount}</span>}
            </button>
          ))}
        </div>
      </div>
      <div className="main">
        {!["summary","clients","notif"].includes(tab)&&(
          <div className="date-nav">
            <span style={{fontWeight:700,color:"var(--accent)"}}>📅</span>
            <input type="date" value={date} onChange={e=>setDate(e.target.value)} style={{width:165}}/>
            <button className="btn btn-ghost btn-sm" onClick={()=>setDate(today())}>Oggi</button>
            <span className="muted" style={{fontStyle:"italic",fontSize:".82rem"}}>{fmt(date)}</span>
          </div>
        )}
        {tab==="menu"    &&<AdminMenu    date={date} appState={appState} update={update}/>}
        {tab==="orders"  &&<AdminOrders  date={date} appState={appState} update={update}/>}
        {tab==="notif"   &&<AdminNotifications       appState={appState} update={update}/>}
        {tab==="clients" &&<AdminClients             appState={appState} update={update}/>}
        {tab==="riepilogo"&&<AdminRiepilogo date={date} appState={appState}/>}
        {tab==="summary" &&<AdminSummary             appState={appState}/>}
      </div>
    </div>
  );
}

// ════════════════════════════════════════════════════════════════════════════
// CLIENT PANEL
// ════════════════════════════════════════════════════════════════════════════
function ClientPanel({ user, appState, update, onLogout }) {
  const [tab,        setTab]        = useState("order");
  const [quantities, setQuantities] = useState({});
  const [customDish, setCustomDish] = useState("");
  const [orderNote,  setOrderNote]  = useState("");
  const [itemNotes,  setItemNotes]  = useState({}); // {itemId: "nota"}
  const [editingCustomId, setEditingCustomId] = useState(null);
  const [editingCustomName, setEditingCustomName] = useState("");
  const [accName,  setAccName]  = useState(user.name);
  const [accPwd,   setAccPwd]   = useState("");
  const [accPwd2,  setAccPwd2]  = useState("");
  const [accToast, setAccToast] = useState("");
  const saveAccount = () => {
    if(accName.trim().length<2) return setAccToast("Nome troppo corto");
    if(accPwd && accPwd.length<4) return setAccToast("Password troppo corta (min 4)");
    if(accPwd && accPwd!==accPwd2) return setAccToast("Le password non coincidono");
    const updUsers = appState.users.map(u=>u.id===user.id?{...u,name:accName.trim(),...(accPwd?{password:accPwd}:{})}:u);
    update({users:updUsers});
    handleLogin({...user,name:accName.trim()});
    setAccPwd(""); setAccPwd2("");
    setAccToast("✓ Profilo aggiornato!");
    setTimeout(()=>setAccToast(""),3000);
    // Mostra un alert per confermare
    setTimeout(()=>window.alert("✓ Profilo aggiornato con successo!"),100);
  };
  const [toast,      setToast]      = useState("");
  const [showIosBanner, setShowIosBanner] = useState(false);
  const [showNotifBanner, setShowNotifBanner] = useState(false);
  const date=today();
  // Ricarica ogni 3 secondi per aggiornare stato ordini in tempo reale
  const [tick, setTick] = useState(0);
  useEffect(()=>{ const t=setInterval(()=>setTick(p=>p+1),2000); return()=>clearInterval(t); },[]);

  // Mostra banner iOS solo se: è iOS, non è già installata, non è stata chiusa
  useEffect(() => {
    const isIos = /iphone|ipad|ipod/i.test(navigator.userAgent);
    const isInstalled = window.navigator.standalone === true;
    const dismissed = localStorage.getItem("ios_banner_dismissed");
    if (isIos && !isInstalled && !dismissed) setShowIosBanner(true);
    // Mostra banner notifiche se non ancora concesse
    if ('Notification' in window && Notification.permission === 'default') {
      const notifDismissed = localStorage.getItem("notif_banner_dismissed");
      if (!notifDismissed) setShowNotifBanner(true);
    }
  }, []);

  const menu        = appState.menus[date]||[];
  const published   = appState.menuPub[date]||false;
  const ordersOpen  = (tick >= 0) && isOrdersOpen(date, appState); // tick forza ricalcolo ogni 3s
  const myOrder   = appState.orders[`${date}:${user.id}`]||null;
  const credit    = appState.credits[user.id]||0;
  const unpaid    = getUserDebt(user.id, appState.orders);
  const myNotifs  = appState.notifications[user.id]||[];
  const unreadCount=myNotifs.filter(n=>!n.read).length;

  const setQty=(id,delta)=>setQuantities(p=>({...p,[id]:Math.max(0,(p[id]||0)+delta)}));

  // Add custom dish request to today's menu
  const addCustomDish=()=>{
    if(!customDish.trim()) return;
    const newItem={id:Date.now().toString(),name:customDish.trim(),price:null,custom:true,requestedBy:user.name};
    const curMenu=appState.menus[date]||[];
    // Avoid duplicate custom requests from same user
    if(curMenu.find(i=>i.custom&&i.requestedBy===user.name&&i.name.toLowerCase()===customDish.trim().toLowerCase())){
      setToast("Piatto già aggiunto!"); setTimeout(()=>setToast(""),2000); return;
    }
    update({menus:{...appState.menus,[date]:[...curMenu,newItem]}});
    setQuantities(prev=>({...prev,[newItem.id]:1}));
    setCustomDish("");
    setToast("✓ Richiesta inviata! Aggiunto al carrello."); setTimeout(()=>setToast(""),2500);
  };

  const sendOrder=()=>{
    const items=menu.filter(i=>(quantities[i.id]||0)>0).map(i=>({...i,qty:quantities[i.id]}));
    if(!items.length){setToast("Seleziona almeno un piatto!");setTimeout(()=>setToast(""),2000);return;}
    const rawTotal=items.reduce((s,i)=>s+(i.price||0)*i.qty,0);
    const creditUsed=credit>0?Math.min(credit,rawTotal):0;
    const netTotal=Math.max(0,rawTotal-creditUsed);
    const newCredits={...appState.credits,[user.id]:r2(credit-creditUsed)};
    // Aggiungi note per piatto agli items
    const itemsWithNotes = items.map(i=>({...i, note:(itemNotes[i.id]||"").trim()||undefined}));
    const order={userId:user.id,userName:user.name,date,items:itemsWithNotes,rawTotal,creditUsed,total:netTotal,paid:false,note:orderNote.trim(),createdAt:new Date().toISOString()};
    // Se il credito copre tutto l'ordine, segna automaticamente come pagato
    // MA solo se non ci sono piatti custom senza prezzo (che verranno prezzati dopo)
    const hasUnpricedItems = items.some(i=>i.price==null||i.price===0);
    if(netTotal===0 && creditUsed>0 && !hasUnpricedItems) order.paid = true;
    const patchOrder={orders:{...appState.orders,[`${date}:${user.id}`]:order},credits:newCredits};
    update(patchOrder);
    setQuantities({});
    setOrderNote("");
    setItemNotes({});
    setToast(netTotal===0?"✓ Ordine pagato con credito!":"✓ Ordine inviato!"); setTimeout(()=>setToast(""),3000);
  };

  const cancelOrder=()=>{
    const newCredits=myOrder?.creditUsed>0
      ?{...appState.credits,[user.id]:r2(credit+(myOrder.creditUsed||0))}
      :appState.credits;
    const newOrders={...appState.orders}; delete newOrders[`${date}:${user.id}`];
    const patchCancel={orders:newOrders,credits:newCredits};
    update(patchCancel);
  };

  const fullCancelOrder=()=>{
    cancelOrder();
    setQuantities({});
  };

  const openNotifs=()=>{
    setTab("notifs");
    const upd={...appState.notifications,[user.id]:myNotifs.map(n=>({...n,read:true}))};
    update({notifications:upd});
  };

  const estRaw  =menu.reduce((s,i)=>s+(i.price||0)*(quantities[i.id]||0),0);
  const crUsable=credit>0?Math.min(credit,estRaw):0;
  const estNet  =Math.max(0,estRaw-crUsable);

  // Separate normal and custom menu items
  // Piatti custom con prezzo → visibili a tutti nella categoria richieste
  // Piatti custom senza prezzo → visibili solo al richiedente
  const normalMenu=menu.filter(i=>!i.custom || (i.custom && i.price!=null));
  const myCustom =menu.filter(i=>i.custom&&i.price==null&&i.requestedBy===user.name);

  return(
    <div className="app">
      {showNotifBanner && (
        <div style={{
          background:"linear-gradient(135deg,#1a3a2e,#0d2b1e)",
          color:"#fff", padding:"12px 16px",
          display:"flex", alignItems:"center", justifyContent:"space-between",
          gap:"10px", fontSize:".82rem", lineHeight:"1.4",
          borderBottom:"2px solid rgba(46,200,100,.4)"
        }}>
          <span>🔔 <b>Attiva le notifiche!</b><br/>
            Ricevi avvisi quando il menù è pronto o gli ordini aprono.
          </span>
          <div style={{display:"flex",gap:6,flexShrink:0}}>
            <button onClick={async()=>{
              const perm = await Notification.requestPermission();
              if(perm==='granted') {
                setShowNotifBanner(false);
                localStorage.setItem("notif_banner_dismissed","1");
                // Ottieni token FCM e salvalo subito
                try {
                  await window.initFirebase();
                  // Aspetta che il token sia disponibile
                  await new Promise(r=>setTimeout(r,2000));
                  if(window._fcmToken && user) {
                    const newTokens = {...(appState.fcmTokens||{}), [user.id]: window._fcmToken};
                    update({fcmTokens: newTokens});
                  }
                } catch(e) { console.error('Token save error:', e); }
              } else {
                setShowNotifBanner(false);
                localStorage.setItem("notif_banner_dismissed","1");
              }
            }} style={{background:"#2ec864",border:"none",color:"#fff",borderRadius:6,padding:"5px 10px",cursor:"pointer",fontSize:".8rem",fontWeight:700}}>
              Attiva
            </button>
            <button onClick={()=>{ localStorage.setItem("notif_banner_dismissed","1"); setShowNotifBanner(false); }}
              style={{background:"rgba(255,255,255,.15)",border:"none",color:"#fff",borderRadius:"50%",width:"26px",height:"26px",cursor:"pointer",fontSize:"1rem"}}>✕</button>
          </div>
        </div>
      )}

      {showIosBanner && (
        <div style={{
          background:"linear-gradient(135deg,#1a1a2e,#16213e)",
          color:"#fff", padding:"12px 16px",
          display:"flex", alignItems:"center", justifyContent:"space-between",
          gap:"10px", fontSize:".82rem", lineHeight:"1.4",
          borderBottom:"2px solid rgba(200,148,42,.4)"
        }}>
          <span>📱 <b>Aggiungi alla schermata Home!</b><br/>
            Tocca <b>Condividi</b> (↑) → <b>"Aggiungi a schermata Home"</b>
          </span>
          <button onClick={()=>{ localStorage.setItem("ios_banner_dismissed","1"); setShowIosBanner(false); }}
            style={{background:"rgba(255,255,255,.15)",border:"none",color:"#fff",borderRadius:"50%",
              width:"26px",height:"26px",cursor:"pointer",fontSize:"1rem",flexShrink:0}}>✕</button>
        </div>
      )}
      <div className="header">
        <div className="header-top">
          <div className="header-logo"><LogoIcon size={42}/>{!BRAND.logoUrl && BRAND.name}</div>
          <div className="header-actions" style={{flex:1,minWidth:0,overflow:"hidden"}}>
            <div style={{display:"flex",gap:4,overflowX:"auto",scrollbarWidth:"none",WebkitOverflowScrolling:"touch"}}>
            <button className={`tab ${tab==="order"?"active":""}`} onClick={()=>setTab("order")}>🍽 Ordina</button>
            <button className={`tab ${tab==="storico"?"active":""}`} onClick={()=>setTab("storico")}>📋</button>
            <button className={`tab ${tab==="account"?"active":""}`} onClick={()=>setTab("account")}>⚙️</button>
            <button className={`tab ${tab==="notifs"?"active":""}`} onClick={openNotifs}>
              🔔{unreadCount>0&&<span className="badge badge-red" style={{marginLeft:3}}>{unreadCount}</span>}
            </button>
            </div>
            <button className="tab" onClick={onLogout} style={{flexShrink:0,marginLeft:4}}>← Esci</button>
          </div>
        </div>
        <div style={{padding:"0 20px 8px",fontSize:".78rem",color:"rgba(255,255,255,.7)"}}>
          Ciao, <b style={{color:"#fff"}}>{user.name}</b>
          {credit>0&&<span style={{marginLeft:10,background:"rgba(255,255,255,.15)",borderRadius:20,padding:"2px 9px",fontWeight:700,color:"#fff"}}>💳 Credito {eur(credit)}</span>}
          {unpaid>0&&<span style={{marginLeft:6,background:"rgba(192,57,43,.4)",borderRadius:20,padding:"2px 9px",fontWeight:700,color:"#fff"}}>⚠ Devi {eur(unpaid)}</span>}
        </div>
      </div>
      <div className="main">

        {tab==="notifs"&&(
          <div className="card">
            <div className="card-title">🔔 Notifiche</div>
            {myNotifs.length===0&&<div className="empty">Nessuna notifica.</div>}
            {myNotifs.map(n=>(
              <div key={n.id} className="notif-item">
                <div className={`notif-dot ${n.read?"read":""}`}/>
                <div style={{flex:1}}>
                  <div style={{fontSize:".88rem",fontWeight:n.read?400:700}}>{n.text||n.message||""}</div>
                  <div className="muted mt4">{n.date ? new Date(n.date).toLocaleString("it-IT",{day:"numeric",month:"short",hour:"2-digit",minute:"2-digit"}) : ""}</div>
                </div>
              </div>
            ))}
          </div>
        )}

        {tab==="account"&&(
          <div className="card">
            <div className="card-title">⚙️ Il mio account</div>
            <div className="field" style={{marginBottom:10}}>
              <label>Nome visualizzato</label>
              <input value={accName} onChange={e=>setAccName(e.target.value)} placeholder="Il tuo nome"/>
            </div>
            <div className="field" style={{marginBottom:10}}>
              <label>Nuova password</label>
              <input type="password" value={accPwd} onChange={e=>setAccPwd(e.target.value)} placeholder="Lascia vuoto per non cambiarla"/>
            </div>
            <div className="field" style={{marginBottom:14}}>
              <label>Conferma password</label>
              <input type="password" value={accPwd2} onChange={e=>setAccPwd2(e.target.value)} placeholder="Ripeti la nuova password"/>
            </div>
            {accToast&&<div className={`toast ${accToast.startsWith("✓")?"":"toast-err"}`} style={{position:"relative",marginBottom:10}}>{accToast}</div>}
            <button className="btn btn-primary" onClick={saveAccount}>💾 Salva modifiche</button>
          </div>
        )}

        {tab==="storico"&&(()=>{
          // Calcola gli ultimi 30 giorni
          const now = new Date();
          const days = [];
          for(let i=29;i>=0;i--){
            const d = new Date(now);
            d.setDate(now.getDate()-i);
            days.push(d.toISOString().slice(0,10));
          }
          // Filtra solo i giorni con ordini
          const daysWithOrders = days.filter(d=>appState.orders[`${d}:${user.id}`]);
          return(
            <div className="card">
              <div className="card-title">📋 I miei ordini (ultimi 30 giorni)</div>
              {daysWithOrders.length===0&&<div className="empty">Nessun ordine nell'ultimo mese.</div>}
              {daysWithOrders.map((d)=>{
                const ord = appState.orders[`${d}:${user.id}`];
                const isToday = d===today();
                return(
                  <div key={d} style={{
                    borderBottom:"1px solid var(--border-lt)", padding:"10px 0"
                  }}>
                    <div className="flex" style={{justifyContent:"space-between",marginBottom:4}}>
                      <span style={{fontWeight:700,color:isToday?"var(--accent)":"var(--text)"}}>
                        {isToday?"📍 ":""}{new Date(d+"T12:00:00").toLocaleDateString("it-IT",{weekday:"short",day:"numeric",month:"short"})}
                      </span>
                      {ord
                        ? <span className={`paid-badge ${ord.paid?"pagato":"non-pagato"}`} style={{cursor:"default",fontSize:".68rem"}}>
                            {ord.paid?"✓ Pagato":"⏳ Da pagare"}
                          </span>
                        : <span className="muted" style={{fontSize:".78rem"}}>—</span>
                      }
                    </div>
                    {ord
                      ? <>
                          {ord.items.map(it=>(
                            <div key={it.id} className="flex" style={{fontSize:".83rem",justifyContent:"space-between",padding:"2px 0"}}>
                              <span>{it.qty}× {it.name}{it.custom?" 🌟":""}</span>
                              <span style={{color:"var(--muted)"}}>{it.price!=null?eur(it.price*it.qty):"prezzo da definire"}</span>
                            </div>
                          ))}
                          {ord.note&&<div style={{fontSize:".78rem",color:"var(--muted)",marginTop:4,fontStyle:"italic"}}>📝 {ord.note}</div>}
                          <div className="flex" style={{justifyContent:"space-between",marginTop:5,fontWeight:700}}>
                            <span>Totale</span>
                            <span style={{color:"var(--accent)"}}>{eur(ord.total)}</span>
                          </div>
                        </>
                      : <div className="muted" style={{fontSize:".8rem"}}>Nessun ordine</div>
                    }
                  </div>
                );
              })}
            </div>
          );
        })()}

        {tab==="order"&&(<>
          {/* Saldo / Credito banners */}
          {credit>0&&(
            <div className="banner banner-green">
              <div><div style={{fontWeight:700,color:"var(--green)"}}>💳 Hai un credito disponibile</div><div className="muted mt4">Verrà scalato automaticamente al prossimo ordine</div></div>
              <div style={{fontFamily:"'Playfair Display',serif",fontSize:"1.9rem",color:"var(--green)",fontWeight:700}}>{eur(credit)}</div>
            </div>
          )}
          {unpaid>0&&(
            <div className="banner banner-red">
              <div><div style={{fontWeight:700,color:"var(--red)"}}>💳 Importo da saldare</div><div className="muted mt4">Totale ordini non ancora pagati</div></div>
              <div style={{fontFamily:"'Playfair Display',serif",fontSize:"1.9rem",color:"var(--red)",fontWeight:700}}>{eur(unpaid)}</div>
            </div>
          )}
          {unpaid===0&&credit===0&&(
            <div className="banner banner-green" style={{padding:"10px 15px"}}>
              <span style={{fontWeight:700,color:"var(--green)"}}>✅ Sei in pari! Nessun importo da saldare.</span>
            </div>
          )}

          {myOrder?(
            <div className="card">
              <div className="card-title">🍽 Il tuo ordine — {fmt(date)}</div>
              {myOrder.items.map(item=>(
                <div key={item.id}>
                  <div className="menu-order-item" style={{cursor:"default"}}>
                    <div>
                      <div style={{fontWeight:700}}>{item.custom&&"⭐ "}{item.name}</div>
                      <div className="muted mt4">×{item.qty}</div>
                    </div>
                  <span style={{fontWeight:700,color:"var(--accent)"}}>
                    {item.price!=null?eur(item.price*item.qty):<span className="muted" style={{fontSize:".79rem"}}>Prezzo TBD</span>}
                  </span>
                </div>
                {item.note&&<div style={{fontSize:".78rem",color:"var(--muted)",fontStyle:"italic",padding:"2px 4px 6px"}}>📝 {item.note}</div>}
              </div>
              ))}
              <hr className="divider"/>
              {(myOrder.creditUsed||0)>0&&<>
                <div className="flex" style={{justifyContent:"space-between",marginBottom:4}}><span className="muted">Totale lordo:</span><span style={{textDecoration:"line-through",color:"var(--muted)"}}>{eur(myOrder.rawTotal)}</span></div>
                <div className="flex" style={{justifyContent:"space-between",marginBottom:4}}><span style={{color:"var(--green)",fontWeight:700}}>💳 Credito:</span><span style={{color:"var(--green)",fontWeight:700}}>−{eur(myOrder.creditUsed)}</span></div>
              </>}
              <div className="flex" style={{justifyContent:"space-between",marginBottom:11}}>
                <span style={{fontWeight:700}}>Da pagare:</span>
                <span style={{color:"var(--accent)",fontWeight:900,fontSize:"1.2rem"}}>{eur(myOrder.total)}</span>
              </div>
              <div className="flex" style={{justifyContent:"space-between",alignItems:"center"}}>
                <span className={`paid-badge ${myOrder.paid?"pagato":"non-pagato"}`} style={{cursor:"default"}}>
                  {myOrder.paid?"✓ Pagato — Grazie!":"⏳ In attesa di pagamento"}
                </span>
                <div className="flex" style={{gap:6}}>
                  {ordersOpen ? <>
                    <button className="btn btn-ghost btn-sm" onClick={()=>{
                      const q={}; myOrder.items.forEach(i=>{q[i.id]=i.qty;}); setQuantities(q); cancelOrder();
                    }}>✏️ Modifica</button>
                    <button className="btn btn-danger btn-sm" onClick={()=>{
                      if(!window.confirm("Annullare l'ordine?")) return; fullCancelOrder();
                    }}>🗑 Annulla</button>
                  </> : <span className="pending-badge">🔒 Ordini chiusi alle 11:30</span>}
                </div>
              </div>
            </div>
          ):(
            <div className="card">
              <div className="card-title">🍴 Menù — {fmt(date)}</div>
              {!published
                ?<div className="empty">⏳<br/>Il menù non è ancora disponibile.<br/>Ricontrolla tra poco!</div>
                :<>
                  {normalMenu.length===0&&<div className="empty" style={{padding:"16px 0"}}>Nessun piatto nel menù standard.</div>}
                  {CATEGORIE.map(cat=>{
                    const catItems = normalMenu.filter(i=>i.categoria===cat.id||(!i.categoria&&cat.id==="primi"));
                    if(!catItems.length) return null;
                    return(<div key={cat.id}>
                      <div style={{fontSize:".75rem",fontWeight:700,color:"var(--accent)",
                        margin:"12px 0 5px",textTransform:"uppercase",letterSpacing:".04em",
                        borderBottom:"1px solid var(--border-lt)",paddingBottom:3}}>
                        {cat.label}
                      </div>
                      {catItems.map(item=>(
                    <div key={item.id}>
                      <div className="menu-order-item">
                        <div>
                          <div style={{fontWeight:700}}>{item.name}</div>
                          <div className="mt4">{item.price!=null?<span style={{color:"var(--accent)",fontWeight:700}}>{eur(item.price)}</span>:<span className="muted" style={{fontSize:".77rem"}}>Prezzo da definire</span>}</div>
                        </div>
                        <div className="qty-ctrl">
                          <button className="qty-btn" onClick={()=>setQty(item.id,-1)}>−</button>
                          <span className="qty-num">{quantities[item.id]||0}</span>
                          <button className="qty-btn" onClick={()=>setQty(item.id,+1)}>+</button>
                        </div>
                      </div>
                      {(quantities[item.id]||0)>0&&(
                        <input
                          value={itemNotes[item.id]||""}
                          onChange={e=>setItemNotes(p=>({...p,[item.id]:e.target.value}))}
                          placeholder="📝 Nota (es. senza cipolla)..."
                          style={{fontSize:".8rem",margin:"4px 0 6px",borderColor:"var(--border-lt)"}}
                        />
                      )}
                    </div>
                  ))}
                    </div>
                  );})}

                  {/* Custom dishes already requested */}
                  {myCustom.length>0&&(
                    <>
                      <div style={{fontSize:".75rem",fontWeight:700,color:"var(--gold)",margin:"10px 0 6px",textTransform:"uppercase"}}>⭐ Le tue richieste</div>
                      {myCustom.map(item=>(
                        <div key={item.id}>
                          <div className="menu-order-item menu-order-item-custom">
                            <div style={{flex:1}}>
                              {editingCustomId===item.id
                                ? <div className="flex" style={{gap:6}}>
                                    <input value={editingCustomName}
                                      onChange={e=>setEditingCustomName(e.target.value)}
                                      style={{flex:1,fontSize:".85rem"}}
                                      autoFocus
                                    />
                                    <button className="btn btn-success btn-sm" onClick={()=>{
                                      if(!editingCustomName.trim()) return;
                                      const newName=editingCustomName.trim();
                                      const updatedMenu=menu.map(i=>i.id===item.id?{...i,name:newName}:i);
                                      // Aggiorna anche gli ordini esistenti che contengono questo piatto
                                      const newOrders={...appState.orders};
                                      Object.keys(newOrders).filter(k=>k.startsWith(date+":")).forEach(k=>{
                                        const ord=newOrders[k];
                                        if(ord&&ord.items.find(i=>i.id===item.id)){
                                          newOrders[k]={...ord,items:ord.items.map(i=>i.id===item.id?{...i,name:newName}:i)};
                                        }
                                      });
                                      update({menus:{...appState.menus,[date]:updatedMenu},orders:newOrders});
                                      setEditingCustomId(null);
                                    }}>✓</button>
                                    <button className="btn btn-ghost btn-sm" onClick={()=>setEditingCustomId(null)}>✕</button>
                                  </div>
                                : <div className="flex" style={{alignItems:"center",gap:6}}>
                                    <div style={{fontWeight:700}}>{item.name}</div>
                                    <button className="btn btn-ghost btn-xs" onClick={()=>{setEditingCustomId(item.id);setEditingCustomName(item.name);}}
                                      style={{fontSize:".7rem",padding:"2px 6px"}}>✏️</button>
                                  </div>
                              }
                              <div className="mt4">{item.price!=null?<span style={{color:"var(--accent)",fontWeight:700}}>{eur(item.price)}</span>:<span className="muted" style={{fontSize:".77rem"}}>In attesa del prezzo</span>}</div>
                            </div>
                            <div className="qty-ctrl">
                              <button className="qty-btn" onClick={()=>setQty(item.id,-1)}>−</button>
                              <span className="qty-num">{quantities[item.id]||0}</span>
                              <button className="qty-btn" onClick={()=>setQty(item.id,+1)}>+</button>
                            </div>
                          </div>
                          {(quantities[item.id]||0)>0&&(
                            <input
                              value={itemNotes[item.id]||""}
                              onChange={e=>setItemNotes(p=>({...p,[item.id]:e.target.value}))}
                              placeholder="📝 Nota per questo piatto..."
                              style={{fontSize:".8rem",margin:"4px 0 6px",borderColor:"var(--gold)"}}
                            />
                          )}
                        </div>
                      ))}
                    </>
                  )}

                  {/* Custom dish request box */}
                  <div style={{background:"var(--bg)",borderRadius:10,padding:"12px 14px",border:"1px solid var(--border)",marginTop:10}}>
                    <div style={{fontSize:".75rem",fontWeight:700,color:"var(--gold)",marginBottom:7,textTransform:"uppercase"}}>⭐ Vuoi qualcosa di diverso?</div>
                    <div className="flex">
                      <input placeholder="Scrivi il tuo piatto personalizzato..." value={customDish} onChange={e=>setCustomDish(e.target.value)} onKeyDown={e=>e.key==="Enter"&&addCustomDish()} style={{flex:1}}/>
                      <button className="btn btn-gold btn-sm" onClick={addCustomDish}>Richiedi</button>
                    </div>
                    <div className="muted mt4" style={{fontSize:".72rem"}}>Il cuoco vedrà la tua richiesta e inserirà il prezzo</div>
                  </div>

                  <hr className="divider"/>
                  {crUsable>0&&<>
                    <div className="flex" style={{justifyContent:"space-between",marginBottom:4}}><span className="muted">Totale lordo:</span><span style={{textDecoration:"line-through",color:"var(--muted)"}}>{eur(estRaw)}</span></div>
                    <div className="flex" style={{justifyContent:"space-between",marginBottom:4}}><span style={{color:"var(--green)",fontWeight:700}}>💳 Credito:</span><span style={{color:"var(--green)",fontWeight:700}}>−{eur(crUsable)}</span></div>
                  </>}
                  <div className="flex" style={{justifyContent:"space-between",marginBottom:11}}>
                    <span style={{fontWeight:700}}>Da pagare:</span>
                    <span style={{color:"var(--accent)",fontWeight:900,fontSize:"1.1rem"}}>{eur(estNet)}</span>
                  </div>

                  <div style={{display:"flex",justifyContent:"flex-end"}}>
                    {ordersOpen
                      ? <button className="btn btn-primary" onClick={sendOrder}>📨 Invia ordine</button>
                      : <div className="pending-badge">🔒 Ordini chiusi alle 11:30</div>
                    }
                  </div>
                </>
              }
            </div>
          )}
        </>)}
      </div>
      {toast&&<div className="toast">{toast}</div>}
    </div>
  );
}
